configfiles.configfile:
import json

options = {}

spatial = "${sec_vitessce_options.spatial}"

spatial_mapping = "${sec_vitessce_options.mappings_spatial_conditional.mappings_spatial}"

pca_mapping = "${sec_vitessce_options.mappings_pca_conditional.mappings_pca}"
pca_value = "${sec_vitessce_options.mappings_pca_conditional.pca_value}"

umap_mapping = "${sec_vitessce_options.mappings_umap_conditional.mappings_umap}"
umap_value = "${sec_vitessce_options.mappings_umap_conditional.umap_value}"

factors= "${sec_vitessce_options.factors}"

sets = "${sec_vitessce_options.sets}"

matrix = "${sec_vitessce_options.matrix}"

## spatial
if spatial:
    options["spatial"] = {
        "xy": f"obsm/{spatial}"
    }

## mappings
mappings = {}

if spatial_mapping == "true" and spatial:
    spatial_dim1 = int("${sec_vitessce_options.mappings_spatial_conditional.spatial_dim1}")
    spatial_dim2 = int("${sec_vitessce_options.mappings_spatial_conditional.spatial_dim2}")
    mappings[f"obsm/{spatial}"] = [spatial_dim1, spatial_dim2]

if pca_mapping == "true":
    pca_dim1 = int("${sec_vitessce_options.mappings_pca_conditional.pca_dim1}")
    pca_dim2 = int("${sec_vitessce_options.mappings_pca_conditional.pca_dim2}")
    mappings[f"obsm/{pca_value}"] = [pca_dim1, pca_dim2]

if umap_mapping == "true":
    umap_dim1 = int("${sec_vitessce_options.mappings_umap_conditional.umap_dim1}")
    umap_dim2 = int("${sec_vitessce_options.mappings_umap_conditional.umap_dim2}")
    mappings[f"obsm/{umap_value}"] = [umap_dim1, umap_dim2]

if mappings:
    options["mappings"] = mappings

## factors
if factors:
    options["factors"] = [f"obs/{f.strip()}" for f in factors.split(",") if f.strip()]

## sets
if sets:
    parsed_sets = []

    for s in sets.split(","):
        s = s.strip()
        if not s:
            continue

        if ":" in s:
            name, score = [x.strip() for x in s.split(":", 1)]
            parsed_sets.append({"name": f"obs/{name}","score": f"obs/{score}"})
        else:
            parsed_sets.append(f"obs/{s}")

options["sets"] = parsed_sets

## matrix
if matrix:
    options["matrix"] = matrix

with open("options.json", "w") as file:
    json.dump(options, file, indent=2)
